import { configureStore, createSlice } from '@reduxjs/toolkit';

// ============================================
// 1. Theme Slice - 다크모드/라이트모드 전역 상태 관리
// ============================================
const themeSlice = createSlice({
  name: 'theme',
  initialState: {
    mode: localStorage.getItem('theme') || 'light',
  },
  reducers: {
    toggleTheme: (state) => {
      state.mode = state.mode === 'light' ? 'dark' : 'light';
      localStorage.setItem('theme', state.mode);
    },
    setTheme: (state, action) => {
      state.mode = action.payload;
      localStorage.setItem('theme', state.mode);
    },
  },
});

// ============================================
// 2. Projects Slice - 프로젝트 데이터 상태 관리
// ============================================
const projectsSlice = createSlice({
  name: 'projects',
  initialState: {
    items: [],
    loading: false,
    error: null,
    filter: 'all', // 'all', 'ai', 'web', 'app'
    searchQuery: '',
  },
  reducers: {
    setProjects: (state, action) => {
      state.items = action.payload;
      state.loading = false;
    },
    setLoading: (state, action) => {
      state.loading = action.payload;
    },
    setError: (state, action) => {
      state.error = action.payload;
      state.loading = false;
    },
    setFilter: (state, action) => {
      state.filter = action.payload;
    },
    setSearchQuery: (state, action) => {
      state.searchQuery = action.payload;
    },
  },
});

// ============================================
// 3. UI Slice - UI 관련 전역 상태 (모달, 사이드바 등)
// ============================================
const uiSlice = createSlice({
  name: 'ui',
  initialState: {
    isModalOpen: false,
    selectedProject: null,
    isMobileMenuOpen: false,
    activeSection: 'home',
  },
  reducers: {
    openModal: (state, action) => {
      state.isModalOpen = true;
      state.selectedProject = action.payload;
    },
    closeModal: (state) => {
      state.isModalOpen = false;
      state.selectedProject = null;
    },
    toggleMobileMenu: (state) => {
      state.isMobileMenuOpen = !state.isMobileMenuOpen;
    },
    closeMobileMenu: (state) => {
      state.isMobileMenuOpen = false;
    },
    setActiveSection: (state, action) => {
      state.activeSection = action.payload;
    },
  },
});

// ============================================
// 4. Visitor Slice - 방문자 수 관리
// ============================================
const visitorSlice = createSlice({
  name: 'visitor',
  initialState: {
    count: 0,
    hasVisited: sessionStorage.getItem('hasVisited') === 'true',
  },
  reducers: {
    setVisitorCount: (state, action) => {
      state.count = action.payload;
    },
    incrementVisitor: (state) => {
      if (!state.hasVisited) {
        state.count += 1;
        state.hasVisited = true;
        sessionStorage.setItem('hasVisited', 'true');
      }
    },
  },
});

// ============================================
// 5. Guestbook Slice - 방명록 관리 (CRUD)
// ============================================
const guestbookSlice = createSlice({
  name: 'guestbook',
  initialState: {
    entries: [],
    loading: false,
    error: null,
  },
  reducers: {
    setGuestbookEntries: (state, action) => {
      state.entries = action.payload;
      state.loading = false;
    },
    addGuestbookEntry: (state, action) => {
      state.entries.unshift(action.payload);
    },
    deleteGuestbookEntry: (state, action) => {
      state.entries = state.entries.filter(entry => entry.id !== action.payload);
    },
    setGuestbookLoading: (state, action) => {
      state.loading = action.payload;
    },
    setGuestbookError: (state, action) => {
      state.error = action.payload;
      state.loading = false;
    },
  },
});

// Export actions
export const { toggleTheme, setTheme } = themeSlice.actions;
export const { setProjects, setLoading, setError, setFilter, setSearchQuery } = projectsSlice.actions;
export const { openModal, closeModal, toggleMobileMenu, closeMobileMenu, setActiveSection } = uiSlice.actions;
export const { setVisitorCount, incrementVisitor } = visitorSlice.actions;
export const { setGuestbookEntries, addGuestbookEntry, deleteGuestbookEntry, setGuestbookLoading, setGuestbookError } = guestbookSlice.actions;

// ============================================
// Configure Store - 모든 리듀서 통합
// ============================================
const store = configureStore({
  reducer: {
    theme: themeSlice.reducer,
    projects: projectsSlice.reducer,
    ui: uiSlice.reducer,
    visitor: visitorSlice.reducer,
    guestbook: guestbookSlice.reducer,
  },
});

export default store;
